import React, { useEffect, useState } from "react";

const Profile = () => {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const fetchUser = async () => {
      const email = localStorage.getItem("email");
      if (!email) return alert("No email found in localStorage");

      try {
        const response = await fetch(`http://127.0.0.1:8000/get_user/?email=${email}`);
        const data = await response.json();

        if (response.ok) {
          setUser(data);
        } else {
          alert(data.error || "Failed to fetch user data");
        }
      } catch (error) {
        console.error("Error fetching user:", error);
        alert("Something went wrong");
      }
    };

    fetchUser();
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-100 via-blue-100 to-yellow-100 flex justify-center items-center px-4">
      <div className="w-full max-w-md bg-white rounded-xl shadow-md p-8">
        <div className="flex flex-col items-center">
          <img
            src="https://i.pravatar.cc/150?img=3"
            alt="Profile"
            className="w-24 h-24 rounded-full shadow-md mb-4"
          />
          <h2 className="text-2xl font-semibold text-gray-800">
            {user?.name || "Loading..."}
          </h2>
          <p className="text-gray-500">{user?.email}</p>

          <button className="mt-6 px-6 py-2 bg-blue-500 text-white rounded-md hover:bg-blue-600 transition">
            Edit Profile
          </button>
        </div>
      </div>
    </div>
  );
};

export default Profile;
